//
// Tests for memory-driven lint (#1901) — focus on the SECURITY contract:
// no eval, prototype-pollution guard, block-severity rejection, and graceful
// degradation on malformed memory files.

import { describe, it, expect, afterEach } from 'vitest';
import { mkdtempSync, writeFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import {
  compilePredicate,
  extractLintBlock,
  loadMemoryRulesFromDir,
  resolveMemoryDir,
  getMemoryRules,
  _resetMemoryRuleCache,
} from '../../lib/memory-lint.js';
import { toolInvocationLinter } from '../../pretool/tool-invocation-linter.js';

const tmpDirs: string[] = [];
function mkDir(): string {
  const d = mkdtempSync(join(tmpdir(), 'memlint-'));
  tmpDirs.push(d);
  return d;
}
function writeFeedback(dir: string, name: string, blockJson: string): void {
  writeFileSync(join(dir, name), `---\nname: x\n---\n\nsome prose\n\n\`\`\`ork-lint\n${blockJson}\n\`\`\`\n`);
}
afterEach(() => {
  for (const d of tmpDirs) rmSync(d, { recursive: true, force: true });
  tmpDirs.length = 0;
  _resetMemoryRuleCache();
});

describe('compilePredicate — safe DSL, no eval', () => {
  it('eq matches exactly; non-match and missing field are false', () => {
    const p = compilePredicate({ field: 'isolation', op: 'eq', value: 'worktree' });
    expect(p({ isolation: 'worktree' })).toBe(true);
    expect(p({ isolation: 'inline' })).toBe(false);
    expect(p({})).toBe(false);
  });

  it('in / exists / absent / prefix / contains', () => {
    expect(compilePredicate({ field: 'mode', op: 'in', value: ['a', 'b'] })({ mode: 'b' })).toBe(true);
    expect(compilePredicate({ field: 'mode', op: 'in', value: ['a', 'b'] })({ mode: 'c' })).toBe(false);
    expect(compilePredicate({ field: 'x', op: 'exists' })({ x: 1 })).toBe(true);
    expect(compilePredicate({ field: 'x', op: 'absent' })({})).toBe(true);
    expect(compilePredicate({ field: 'cmd', op: 'prefix', value: 'rm ' })({ cmd: 'rm -rf /' })).toBe(true);
    expect(compilePredicate({ field: 'cmd', op: 'contains', value: 'rm -rf' })({ cmd: 'x && rm -rf y' })).toBe(true);
  });

  it('resolves nested dot-paths', () => {
    expect(compilePredicate({ field: 'a.b', op: 'eq', value: 'v' })({ a: { b: 'v' } })).toBe(true);
    expect(compilePredicate({ field: 'a.b', op: 'eq', value: 'v' })({ a: {} })).toBe(false);
  });

  it('SECURITY: refuses prototype-pollution keys', () => {
    expect(compilePredicate({ field: '__proto__', op: 'exists' })({})).toBe(false);
    expect(compilePredicate({ field: 'a.constructor', op: 'exists' })({ a: {} })).toBe(false);
    expect(compilePredicate({ field: 'prototype', op: 'exists' })({})).toBe(false);
  });

  it('SECURITY: a JS-looking value is a literal string, never executed', () => {
    const p = compilePredicate({ field: 'x', op: 'eq', value: 'process.exit(1)' });
    expect(p({ x: 'process.exit(1)' })).toBe(true); // literal compare, process still alive
    expect(p({ x: 'safe' })).toBe(false);
  });
});

describe('extractLintBlock', () => {
  it('extracts the fenced block, or null when absent/unterminated', () => {
    expect(extractLintBlock('no block here')).toBeNull();
    expect(extractLintBlock('```ork-lint\n[]\n```')).toBe('[]');
    expect(extractLintBlock('```ork-lint\n[] but never closed')).toBeNull();
  });
});

describe('loadMemoryRulesFromDir', () => {
  it('loads + compiles a valid rule, tagged with its source file', () => {
    const d = mkDir();
    writeFeedback(d, 'feedback_iso.md',
      '[{"id":"agent-iso","tool_name":"Agent","predicate":{"field":"isolation","op":"eq","value":"worktree"},"severity":"warn","message":"broken on CC <=2.1.153","see":"#1883"}]');
    const { rules, errors } = loadMemoryRulesFromDir(d);
    expect(errors).toEqual([]);
    expect(rules).toHaveLength(1);
    expect(rules[0].id).toBe('agent-iso');
    expect(rules[0].source).toBe('memory:feedback_iso.md');
    expect(rules[0].predicate({ isolation: 'worktree' })).toBe(true);
  });

  it('rejects non-kebab id and unknown op, collecting errors (no throw)', () => {
    const d = mkDir();
    writeFeedback(d, 'feedback_bad.md',
      '[{"id":"NotKebab","tool_name":"Agent","predicate":{"field":"x","op":"eq","value":"y"},"message":"m","see":"s"},' +
      '{"id":"bad-op","tool_name":"Agent","predicate":{"field":"x","op":"regex","value":"y"},"message":"m","see":"s"}]');
    const { rules, errors } = loadMemoryRulesFromDir(d);
    expect(rules).toHaveLength(0);
    expect(errors).toHaveLength(2);
  });

  it('SECURITY: rejects severity:block — memory rules may not halt tools', () => {
    const d = mkDir();
    writeFeedback(d, 'feedback_block.md',
      '[{"id":"try-block","tool_name":"Bash","predicate":{"field":"command","op":"contains","value":"rm"},"severity":"block","message":"m","see":"s"}]');
    const { rules, errors } = loadMemoryRulesFromDir(d);
    expect(rules).toHaveLength(0);
    expect(errors[0]).toContain('may not block');
  });

  it('records an error on malformed JSON, never throws', () => {
    const d = mkDir();
    writeFeedback(d, 'feedback_malformed.md', '[{not valid json}]');
    const { rules, errors } = loadMemoryRulesFromDir(d);
    expect(rules).toHaveLength(0);
    expect(errors[0]).toContain('invalid JSON');
  });

  it('ignores non-feedback files and feedback files without a block', () => {
    const d = mkDir();
    writeFileSync(join(d, 'MEMORY.md'), '```ork-lint\n[{"id":"x"}]\n```'); // not feedback_*
    writeFileSync(join(d, 'feedback_plain.md'), 'just prose, no lint block');
    const { rules, errors } = loadMemoryRulesFromDir(d);
    expect(rules).toHaveLength(0);
    expect(errors).toEqual([]);
  });

  it('returns empty for a missing directory', () => {
    expect(loadMemoryRulesFromDir('/no/such/dir/at/all')).toEqual({ rules: [], errors: [] });
  });
});

describe('resolveMemoryDir', () => {
  it('honors the ORK_MEMORY_DIR override', () => {
    const prev = process.env.ORK_MEMORY_DIR;
    process.env.ORK_MEMORY_DIR = '/tmp/override';
    expect(resolveMemoryDir('/anything')).toBe('/tmp/override');
    if (prev === undefined) delete process.env.ORK_MEMORY_DIR;
    else process.env.ORK_MEMORY_DIR = prev;
  });

  it('derives ~/.claude/projects/<slug>/memory from cwd', () => {
    const prevHome = process.env.HOME;
    const prevOv = process.env.ORK_MEMORY_DIR;
    delete process.env.ORK_MEMORY_DIR;
    process.env.HOME = '/home/u';
    expect(resolveMemoryDir('/a/b')).toBe('/home/u/.claude/projects/-a-b/memory');
    if (prevHome === undefined) delete process.env.HOME;
    else process.env.HOME = prevHome;
    if (prevOv !== undefined) process.env.ORK_MEMORY_DIR = prevOv;
  });
});

describe('getMemoryRules', () => {
  it('returns [] when ORK_NO_MEMORY_LINT=1', () => {
    const prev = process.env.ORK_NO_MEMORY_LINT;
    process.env.ORK_NO_MEMORY_LINT = '1';
    _resetMemoryRuleCache();
    expect(getMemoryRules('/any')).toEqual([]);
    if (prev === undefined) delete process.env.ORK_NO_MEMORY_LINT;
    else process.env.ORK_NO_MEMORY_LINT = prev;
  });
});

describe('integration: linter applies memory rules', () => {
  it('flags a matching tool call with a [memory:<file>] advisory', () => {
    const d = mkDir();
    writeFeedback(d, 'feedback_int.md',
      '[{"id":"no-no-verify","tool_name":"Bash","predicate":{"field":"command","op":"contains","value":"--no-verify"},"severity":"warn","message":"do not bypass hooks","see":"CLAUDE.md"}]');
    const prevOv = process.env.ORK_MEMORY_DIR;
    const prevOff = process.env.ORK_NO_MEMORY_LINT;
    delete process.env.ORK_NO_MEMORY_LINT;
    process.env.ORK_MEMORY_DIR = d;
    _resetMemoryRuleCache();

    const res = toolInvocationLinter({ tool_name: 'Bash', tool_input: { command: 'git push --no-verify' } } as never);
    const blob = JSON.stringify(res);
    expect(blob).toContain('no-no-verify');
    expect(blob).toContain('memory:feedback_int.md');

    // a non-matching command produces no advisory for this rule
    _resetMemoryRuleCache();
    const clean = JSON.stringify(toolInvocationLinter({ tool_name: 'Bash', tool_input: { command: 'git push' } } as never));
    expect(clean).not.toContain('no-no-verify');

    if (prevOv === undefined) delete process.env.ORK_MEMORY_DIR;
    else process.env.ORK_MEMORY_DIR = prevOv;
    if (prevOff !== undefined) process.env.ORK_NO_MEMORY_LINT = prevOff;
  });
});
